// Pull both r1's and r2's ensures contents into the proof context with
// parallel terms so z3 sees the observable spec components on the same
// triggers. The function's ensures pin is_init() to true and addr() to
// page_index2page_ptr(target_page_idx) for each result independently.
assert(r1@.is_init());
assert(r1@.addr() == page_index2page_ptr(target_page_idx));
assert(r2@.is_init());
assert(r2@.addr() == page_index2page_ptr(target_page_idx));

// Pointwise equality of the spec components named in the ensures.
// Both is_init() flags are forced to true; both addrs() are forced to the
// same concrete ptr — so they are equal by transitivity through the
// shared term page_index2page_ptr(target_page_idx).
assert(r1@.is_init() == r2@.is_init());
assert(r1@.addr() == r2@.addr());
